/* ════════════════════════════════════════════
   abschluss.js – JavaScript für alle
   Abschlussprojekt-Seiten (1–4)
   ════════════════════════════════════════════ */

/* ── Gemeinsame Funktionen ─────────────────── */
function toggleSwitcher(btn) {
  btn.classList.toggle('open');
  document.getElementById('switcherMenu').classList.toggle('open');
}
document.addEventListener('click', function(e) {
  if (!e.target.closest('.switcher-inner')) {
    document.querySelectorAll('.switcher-btn').forEach(function(b) { b.classList.remove('open'); });
    document.querySelectorAll('.switcher-menu').forEach(function(m) { m.classList.remove('open'); });
  }
});
function initSwitcher(cid, label, src) {
  var icon = document.getElementById('switcherIcon');
  var lbl  = document.getElementById('switcherLabel');
  if (icon) { icon.src = src; icon.alt = label; }
  if (lbl)  lbl.textContent = label;
  document.querySelectorAll('.switcher-item').forEach(function(x) {
    if (x.dataset.id === cid) x.classList.add('active');
  });
}
function initToc() {
  document.querySelectorAll('.toc-toggle').forEach(function(btn) {
    btn.addEventListener('click', function() {
      btn.classList.toggle('open');
      btn.nextElementSibling.classList.toggle('open');
    });
  });
}
document.addEventListener('DOMContentLoaded', initToc);


function exportList(data, fmtId, filenameBase) {
  var fmt = document.getElementById(fmtId).value;
  var content = '', mime = '', ext = '';
  if (fmt === 'json') {
    content = JSON.stringify(data, null, 2); mime = 'application/json'; ext = 'json';
  } else if (fmt === 'xml') {
    var tag = filenameBase.replace(/[^a-z]/gi, '_');
    var rows = data.map(function(d, i) {
      var inner = Object.keys(d).map(function(k) {
        return '    <' + k + '>' + String(d[k]).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</' + k + '>';
      }).join('\n');
      return '  <item index="' + (i+1) + '">\n' + inner + '\n  </item>';
    }).join('\n');
    content = '<?xml version="1.0" encoding="UTF-8"?>\n<' + tag + '>\n' + rows + '\n</' + tag + '>';
    mime = 'application/xml'; ext = 'xml';
  } else {
    content = data.map(function(d) {
      return Object.keys(d).map(function(k) { return k + ': ' + d[k]; }).join(' | ');
    }).join('\n');
    mime = 'text/plain'; ext = 'txt';
  }
  var blob = new Blob([content], {type: mime});
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href = url; a.download = filenameBase + '.' + ext; a.click();
  URL.revokeObjectURL(url);
}

/* ── Seite 1 – Witze ───────────────────────── */
if (window.location.pathname.endsWith('abschluss_1_witze.html') || document.title.includes('Witze')) {
var allJokes = [], filtered = [], savedJokes = [];
// Load saved jokes from sessionStorage (persists within tab session)
try { var _sj = sessionStorage.getItem('wmc_savedJokes'); if (_sj) { savedJokes = JSON.parse(_sj); renderSaved(); } } catch(e) {}
var PAGE_SIZE = 6, currentPage = 1;

function loadJokes() {
  var cat = document.getElementById('categorySelect').value;
  var amt = parseInt(document.getElementById('amountSelect').value);
  setStatus('Lade Witze…', 'loading');
  document.getElementById('statsRow').style.display = 'none';
  document.getElementById('jokesGrid').innerHTML = '<div class="empty-state">⏳ Verbinde mit JokeAPI…</div>';

  var urls = [];
  if (amt <= 10) {
    urls.push('https://v2.jokeapi.dev/joke/' + cat + '?amount=' + amt + '&blacklistFlags=nsfw,religious,political,racist,sexist,explicit');
  } else {
    var url10 = 'https://v2.jokeapi.dev/joke/' + cat + '?amount=10&blacklistFlags=nsfw,religious,political,racist,sexist,explicit';
    urls.push(url10, url10);
  }

  Promise.all(urls.map(function(u) { return fetch(u).then(function(r) { return r.json(); }); }))
    .then(function(results) {
      var jokes = [];
      results.forEach(function(data) {
        var arr = Array.isArray(data.jokes) ? data.jokes : [data];
        jokes = jokes.concat(arr);
      });
      allJokes = jokes.map(function(j) {
        return { id: j.id, category: j.category, type: j.type,
                  text: j.type === 'single' ? j.joke : j.setup,
                  delivery: j.type === 'twopart' ? j.delivery : null };
      });
      document.getElementById('searchInput').value = '';
      filterAndRender();
      renderTable();
      setStatus(allJokes.length + ' Witze geladen ✓', 'ok');
    })
    .catch(function(err) {
      setStatus('Fehler: ' + err.message, 'error');
      document.getElementById('jokesGrid').innerHTML = '<div class="empty-state" style="color:#ff9a9a">⚠ ' + err.message + '</div>';
    });
}

function filterAndRender() {
  var q = document.getElementById('searchInput').value.toLowerCase();
  filtered = allJokes.filter(function(j) {
    return j.text.toLowerCase().includes(q) ||
           (j.delivery && j.delivery.toLowerCase().includes(q)) ||
           j.category.toLowerCase().includes(q);
  });
  currentPage = 1;
  renderCards();
  document.getElementById('statTotal').textContent   = allJokes.length;
  document.getElementById('statFiltered').textContent = filtered.length;
  document.getElementById('statsRow').style.display   = allJokes.length ? 'flex' : 'none';
}

function renderCards() {
  var grid = document.getElementById('jokesGrid');
  var pg   = document.getElementById('paginationCards');
  var start = (currentPage - 1) * PAGE_SIZE;
  var page  = filtered.slice(start, start + PAGE_SIZE);
  if (!page.length) { grid.innerHTML = '<div class="empty-state">Keine Einträge gefunden.</div>'; pg.style.display = 'none'; return; }
  grid.innerHTML = '';
  page.forEach(function(j) {
    var card  = document.createElement('div'); card.className = 'item-card';
    var badge = document.createElement('span'); badge.className = 'cat-badge'; badge.textContent = j.category;
    var txt   = document.createElement('p');   txt.className = 'item-text'; txt.textContent = j.text;
    var sv    = document.createElement('button'); sv.className = 'save-btn'; sv.textContent = '💾 Merken';
    sv.onclick = (function(jj) { return function() { saveJoke(jj); }; })(j);
    var id    = document.createElement('span'); id.className = 'item-id'; id.textContent = '#' + j.id;
    card.appendChild(badge); card.appendChild(txt);
    if (j.delivery) {
      var del = document.createElement('p'); del.className = 'item-sub'; del.textContent = j.delivery;
      card.appendChild(del);
    }
    card.appendChild(sv); card.appendChild(id);
    grid.appendChild(card);
  });
  var total = Math.ceil(filtered.length / PAGE_SIZE);
  pg.style.display = total > 1 ? 'flex' : 'none';
  document.getElementById('pageLabel').textContent = 'Seite ' + currentPage + '/' + total;
  document.getElementById('btnPrev').disabled = currentPage === 1;
  document.getElementById('btnNext').disabled = currentPage === total;
}

function renderTable() {
  var tbody = document.getElementById('tableBody');
  if (!allJokes.length) { tbody.innerHTML = '<tr><td colspan="5" style="color:#4a7a5a;">Noch keine Witze.</td></tr>'; return; }
  tbody.innerHTML = '';
  allJokes.forEach(function(j, i) {
    var tr = document.createElement('tr');
    var esc = function(s) { return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); };
    tr.innerHTML = '<td>' + (i+1) + '</td><td>' + j.category + '</td><td>' + j.type + '</td>' +
      '<td style="text-align:left;max-width:300px;white-space:normal;">' + esc(j.text) + '</td>' +
      '<td style="text-align:left;max-width:200px;white-space:normal;color:#7effc0;">' + (j.delivery ? esc(j.delivery) : '—') + '</td>';
    tbody.appendChild(tr);
  });
}

function saveJoke(j) {
  var already = savedJokes.some(function(s) { return s.id === j.id; });
  if (already) return;
  savedJokes.push(j); try { sessionStorage.setItem('wmc_savedJokes', JSON.stringify(savedJokes)); } catch(e) {} renderSaved();
}
function deleteJoke(idx) { savedJokes.splice(idx, 1); try { sessionStorage.setItem('wmc_savedJokes', JSON.stringify(savedJokes)); } catch(e) {} renderSaved(); }
function clearSaved() { savedJokes = []; try { sessionStorage.removeItem('wmc_savedJokes'); } catch(e) {} renderSaved(); }

function renderSaved() {
  document.getElementById('savedCount').textContent = savedJokes.length + ' Witze gespeichert';
  var g = document.getElementById('savedGrid');
  if (!savedJokes.length) { g.innerHTML = '<div class="empty-state">Noch keine Daten gespeichert.</div>'; return; }
  g.innerHTML = '';
  savedJokes.forEach(function(j, i) {
    var card  = document.createElement('div'); card.className = 'item-card';
    var badge = document.createElement('span'); badge.className = 'cat-badge'; badge.textContent = j.category;
    var txt   = document.createElement('p'); txt.className = 'item-text'; txt.textContent = j.text;
    var del   = document.createElement('button'); del.className = 'btn-danger';
    del.style.cssText = 'align-self:flex-start;padding:3px 8px;font-size:0.75rem;';
    del.textContent = '✕';
    del.onclick = (function(ii) { return function() { deleteJoke(ii); }; })(i);
    card.appendChild(badge); card.appendChild(txt);
    if (j.delivery) {
      var d = document.createElement('p'); d.className = 'item-sub'; d.textContent = j.delivery;
      card.appendChild(d);
    }
    card.appendChild(del); g.appendChild(card);
  });
}

function exportSaved() {
  var data = savedJokes.map(function(j) {
    return { id: j.id, category: j.category, type: j.type, text: j.text, punchline: j.delivery || '' };
  });
  exportList(data, 'exportFmt', 'gespeicherte_witze');
}
function changePage(dir) { currentPage += dir; renderCards(); document.getElementById('explorer').scrollIntoView({behavior:'smooth'}); }
function setStatus(msg, type) { var b = document.getElementById('statusBar'); b.textContent = msg; b.className = 'status-bar ' + (type || ''); }

initSwitcher('abschluss', 'JS Abschlussprojekt', 'data:image/png;base64,');
loadJokes();
}

/* ── Seite 2 – Pokémon ─────────────────────── */
if (window.location.pathname.endsWith('abschluss_2_pokemon.html') || document.title.includes('Pokémon')) {
var TYPE_DE = {
  'normal':'Normal','fire':'Feuer','water':'Wasser','electric':'Elektro',
  'grass':'Pflanze','ice':'Eis','fighting':'Kampf','poison':'Gift',
  'ground':'Boden','flying':'Flug','psychic':'Psycho','bug':'Käfer',
  'rock':'Gestein','ghost':'Geist','dragon':'Drache','dark':'Unlicht',
  'steel':'Stahl','fairy':'Fee'
};
var STAT_DE = {
  'hp':'KP','attack':'Angriff','defense':'Verteidigung',
  'special-attack':'Sp.-Angriff','special-defense':'Sp.-Verteidigung','speed':'Initiative'
};

// ── Quiz data ─────────────────────────────────────────────
var QUESTIONS = [
  {q:"Was machen Sie am liebsten am Wochenende?",
    opts:["Zuhause bleiben & entspannen","Sport & Action draußen","Neue Orte erkunden","Freunde treffen & feiern"]},
  {q:"Welches Element spricht Sie am meisten an?",
    opts:["Feuer – leidenschaftlich & energiegeladen","Wasser – ruhig & tiefgründig","Pflanze – geerdet & natürlich","Blitz – schnell & überraschend"]},
  {q:"Wie reagieren Sie auf Herausforderungen?",
    opts:["Direkt drauf los – kein Zögern!","Erst beobachten, dann handeln","Kreativ um das Problem herumgehen","Andere um Hilfe bitten"]},
  {q:"Was ist Ihre größte Stärke?",
    opts:["Kraft & Ausdauer","Intelligenz & Strategie","Anpassungsfähigkeit","Teamgeist & Loyalität"]},
  {q:"Welche Farbe mögen Sie am liebsten?",
    opts:["Rot & Orange – warm & feurig","Blau & Türkis – kühl & ruhig","Grün & Braun – natürlich & satt","Gelb & Gold – strahlend & fröhlich"]},
];
var WEIGHTS = [[10,120,252,494],[4,7,1,25],[99,54,43,175],[68,150,132,113],[6,131,334,135]];
var answers = [];

// ── Quiz functions ────────────────────────────────────────
function buildQuiz() {
  answers = [];
  var box  = document.getElementById('quizBox');
  var dots = document.getElementById('progressDots');
  box.innerHTML = ''; dots.innerHTML = '';
  QUESTIONS.forEach(function(_, i) {
    var s = document.createElement('span');
    dots.appendChild(s);
  });
  renderQuestion(0);
}

function renderQuestion(idx) {
  var box = document.getElementById('quizBox');
  if (idx >= QUESTIONS.length) {
    document.getElementById('btnResult').style.display = 'inline-block';
    box.innerHTML = '<div class="empty-state" style="color:#7effc0;">✓ Alle Fragen beantwortet!</div>';
    return;
  }
  var q = QUESTIONS[idx];
  box.innerHTML = '';
  var qBox = document.createElement('div'); qBox.className = 'quiz-question';
  var p    = document.createElement('p');   p.textContent = (idx+1) + '/' + QUESTIONS.length + ' — ' + q.q;
  var opts = document.createElement('div'); opts.className = 'quiz-options';
  q.opts.forEach(function(opt, oi) {
    var btn = document.createElement('button'); btn.className = 'quiz-option'; btn.textContent = opt;
    btn.onclick = (function(oiCopy) {
      return function() {
        answers.push(oiCopy);
        document.getElementById('progressDots').children[idx].classList.add('done');
        renderQuestion(idx + 1);
      };
    })(oi);
    opts.appendChild(btn);
  });
  qBox.appendChild(p); qBox.appendChild(opts); box.appendChild(qBox);
}

function calcId() {
  var sum = 0;
  answers.forEach(function(a, qi) { sum += WEIGHTS[qi][a]; });
  return Math.max(1, Math.min(898, ((sum % 200) || 1) + (answers.reduce(function(a,b){return a+b;},0) % 200)));
}

// ── Show result (fetch from PokéAPI) ─────────────────────
async function showResult() {
  document.getElementById('btnResult').style.display = 'none';
  document.getElementById('btnRetry').style.display  = 'inline-block';
  var id = calcId();
  setPS('Lade Ihr Pokémon…', 'loading');
  document.getElementById('resultBox').style.display  = 'none';
  document.getElementById('savePngWrap').style.display = 'none';
  try {
    var pr = await fetch('https://pokeapi.co/api/v2/pokemon/' + id);
    var sr = await fetch('https://pokeapi.co/api/v2/pokemon-species/' + id);
    var poke = await pr.json();
    var spec = await sr.json();
    var sprites = poke.sprites && poke.sprites.other && poke.sprites.other['official-artwork'];
    var img  = (sprites && sprites.front_default) || poke.sprites.front_default;
    var types = poke.types.map(function(t) { return t.type.name; });
    var nameEntry = spec.names.find(function(n) { return n.language.name === 'de'; });
    var nameDE = nameEntry ? nameEntry.name : poke.name;
    var descEntry = spec.flavor_text_entries.find(function(e) { return e.language.name === 'de'; })
                 || spec.flavor_text_entries.find(function(e) { return e.language.name === 'en'; });
    var desc = descEntry ? descEntry.flavor_text.split('\f').join(' ').split('\n').join(' ').split('\u000c').join(' ') : 'Keine Beschreibung verfügbar.';

    document.getElementById('pokeImg').src  = img || '';
    document.getElementById('pokeName').textContent = nameDE;
    document.getElementById('pokeTypes').innerHTML  = types.map(function(t) {
      return '<span class="type-badge">' + (TYPE_DE[t] || t) + '</span>';
    }).join('');
    document.getElementById('pokeDesc').textContent = desc;

    var sd = document.getElementById('pokeStats'); sd.innerHTML = '';
    poke.stats.forEach(function(s) {
      var row = document.createElement('div'); row.className = 'stat-bar-row';
      var pct = Math.min(100, (s.base_stat / 255) * 100);
      var lbl = STAT_DE[s.stat.name] || s.stat.name;
      row.innerHTML = '<span>' + lbl + '</span><div class="stat-bar-wrap"><div class="stat-bar-fill" style="width:0%" data-pct="' + pct.toFixed(1) + '"></div></div><span>' + s.base_stat + '</span>';
      sd.appendChild(row);
    });

    document.getElementById('resultBox').style.display   = 'block';
    document.getElementById('savePngWrap').style.display = 'block';
    setPS('', '');
    setTimeout(function() {
      document.querySelectorAll('.stat-bar-fill').forEach(function(b) { b.style.width = b.dataset.pct + '%'; });
    }, 100);
    document.getElementById('ergebnis').scrollIntoView({behavior: 'smooth'});

    // Save to sessionStorage
    try {
      sessionStorage.setItem('wmc_pokemon', JSON.stringify({
        name:  nameDE,
        img:   img,
        types: types,
        desc:  desc,
        stats: poke.stats.map(function(s) { return {name: STAT_DE[s.stat.name] || s.stat.name, value: s.base_stat}; })
      }));
    } catch(ex) { console.warn('SessionStorage save failed:', ex); }

  } catch(err) { setPS('Fehler: ' + err.message, 'error'); }
}

// ── Restart ───────────────────────────────────────────────
function restartQuiz() {
  document.getElementById('btnResult').style.display   = 'none';
  document.getElementById('btnRetry').style.display    = 'none';
  document.getElementById('resultBox').style.display   = 'none';
  document.getElementById('savePngWrap').style.display = 'none';
  setPS('', '');
  try { sessionStorage.removeItem('wmc_pokemon'); } catch(ex) {}
  buildQuiz();
  document.getElementById('quiz').scrollIntoView({behavior: 'smooth'});
}

// ── PNG export ────────────────────────────────────────────
async function savePokePng() {
  var box = document.getElementById('resultBox');
  try {
    var canvas = await html2canvas(box, {backgroundColor: '#1e3a2e', scale: 2, useCORS: true, allowTaint: false});
    var name   = document.getElementById('pokeName').textContent || 'pokemon';
    var a = document.createElement('a');
    a.download = name + '.png';
    a.href = canvas.toDataURL('image/png');
    a.click();
  } catch(e) { alert('PNG-Export fehlgeschlagen: ' + e.message); }
}

// ── Restore from sessionStorage ───────────────────────────
function restoreAndInit() {
  initSwitcher('abschluss', 'JS Abschlussprojekt', 'data:image/png;base64,');
  initToc();
  buildQuiz();
  try {
    var raw = sessionStorage.getItem('wmc_pokemon');
    if (raw) {
      var pk = JSON.parse(raw);
      document.getElementById('pokeImg').src  = pk.img || '';
      document.getElementById('pokeName').textContent = pk.name;
      document.getElementById('pokeTypes').innerHTML  = pk.types.map(function(t) {
        return '<span class="type-badge">' + (TYPE_DE[t] || t) + '</span>';
      }).join('');
      document.getElementById('pokeDesc').textContent = pk.desc;
      var sd = document.getElementById('pokeStats'); sd.innerHTML = '';
      pk.stats.forEach(function(s) {
        var row = document.createElement('div'); row.className = 'stat-bar-row';
        var pct = Math.min(100, (s.value / 255) * 100);
        row.innerHTML = '<span>' + s.name + '</span><div class="stat-bar-wrap"><div class="stat-bar-fill" style="width:0%" data-pct="' + pct.toFixed(1) + '"></div></div><span>' + s.value + '</span>';
        sd.appendChild(row);
      });
      document.getElementById('resultBox').style.display   = 'block';
      document.getElementById('savePngWrap').style.display = 'block';
      document.getElementById('btnRetry').style.display    = 'inline-block';
      setTimeout(function() {
        document.querySelectorAll('.stat-bar-fill').forEach(function(b) { b.style.width = b.dataset.pct + '%'; });
      }, 150);
    }
  } catch(ex) { console.warn('Restore failed:', ex); }
}

document.addEventListener('DOMContentLoaded', restoreAndInit);
window.addEventListener('pageshow', function(e) {
  if (e.persisted) { restoreAndInit(); }
});

function setPS(msg, type) {
  var b = document.getElementById('pokeStatus');
  b.textContent = msg;
  b.className = 'status-bar ' + (type || '');
}
}

/* ── Seite 3 – Zitate ──────────────────────── */
if (window.location.pathname.endsWith('abschluss_3_zitate.html') || document.title.includes('Zitate')) {
var CLASSIC_FALLBACK = [
  {text: "Das Leben ist das, was passiert, während du andere Pläne machst.", author: "John Lennon", source: "lokal"},
  {text: "Sei die Veränderung, die du dir für diese Welt wünschst.", author: "Mahatma Gandhi", source: "lokal"},
  {text: "In der Mitte jeder Schwierigkeit liegt eine Möglichkeit.", author: "Albert Einstein", source: "lokal"},
  {text: "Zwei Dinge sind unendlich: das Universum und die menschliche Dummheit. Beim Universum bin ich noch nicht sicher.", author: "Albert Einstein", source: "lokal"},
  {text: "Das Geheimnis des Erfolgs ist anzufangen.", author: "Mark Twain", source: "lokal"},
  {text: "Der Klügere gibt nach! Eine traurige Wahrheit, sie begründet die Weltherrschaft der Dummheit.", author: "Marie von Ebner-Eschenbach", source: "lokal"},
  {text: "Wer kämpft, kann verlieren. Wer nicht kämpft, hat schon verloren.", author: "Bertolt Brecht", source: "lokal"}
];

var savedQuotes = [], loadedCount = 0, kanyeCount = 0, classicCount = 0;
try { var _sq = sessionStorage.getItem('wmc_savedQuotes'); if (_sq) { savedQuotes = JSON.parse(_sq); document.getElementById('cntSaved').textContent = savedQuotes.length; renderSaved(); } } catch(e) {}

function loadQuote(type) {
  setQS('Lade Zitat…', 'loading');
  if (type === 'kanye') {
    fetch('https://api.kanye.rest/')
      .then(function(r) { return r.json(); })
      .then(function(d) {
        kanyeCount++; loadedCount++;
        document.getElementById('cntKanye').textContent = kanyeCount;
        document.getElementById('cntLoaded').textContent = loadedCount;
        renderQuote({text: d.quote, author: 'Kanye West', source: 'kanye'});
        setQS('', '');
      })
      .catch(function() {
        // Fallback via allorigins
        fetch('https://api.allorigins.win/get?url=' + encodeURIComponent('https://api.kanye.rest/'))
          .then(function(r) { return r.json(); })
          .then(function(wrap) {
            var d = JSON.parse(wrap.contents);
            kanyeCount++; loadedCount++;
            document.getElementById('cntKanye').textContent = kanyeCount;
            document.getElementById('cntLoaded').textContent = loadedCount;
            renderQuote({text: d.quote, author: 'Kanye West', source: 'kanye'});
            setQS('', '');
          })
          .catch(function(err) { setQS('Kanye API nicht erreichbar: ' + err.message, 'error'); });
      });
  } else {
    // dummyjson.com - reliable, CORS-enabled, free
    fetch('https://dummyjson.com/quotes/random')
      .then(function(r) { if (!r.ok) throw new Error('dummyjson ' + r.status); return r.json(); })
      .then(function(d) {
        classicCount++; loadedCount++;
        document.getElementById('cntClassic').textContent = classicCount;
        document.getElementById('cntLoaded').textContent = loadedCount;
        renderQuote({text: d.quote, author: d.author, source: 'dummyjson'});
        setQS('', '');
      })
      .catch(function() {
        // Fallback: zenquotes.io
        fetch('https://zenquotes.io/api/random')
          .then(function(r) { if (!r.ok) throw new Error('zenquotes ' + r.status); return r.json(); })
          .then(function(arr) {
            classicCount++; loadedCount++;
            document.getElementById('cntClassic').textContent = classicCount;
            document.getElementById('cntLoaded').textContent = loadedCount;
            renderQuote({text: arr[0].q, author: arr[0].a, source: 'zenquotes'});
            setQS('', '');
          })
          .catch(function() {
            // Final fallback: local array
            var fb = CLASSIC_FALLBACK[Math.floor(Math.random() * CLASSIC_FALLBACK.length)];
            classicCount++; loadedCount++;
            document.getElementById('cntClassic').textContent = classicCount;
            document.getElementById('cntLoaded').textContent = loadedCount;
            renderQuote(fb);
            setQS('Lokales Zitat (APIs offline)', '');
          });
      });
  }
}

function renderQuote(q) {
  var d = document.getElementById('quoteDisplay'); d.innerHTML = '';
  var card = document.createElement('div'); card.className = 'quote-card' + (q.source === 'kanye' ? ' kanye-card' : '');
  var txt  = document.createElement('div'); txt.className = 'quote-text'; txt.textContent = '"' + q.text + '"';
  var auth = document.createElement('div'); auth.className = 'quote-author'; auth.textContent = '— ' + q.author;
  var src  = document.createElement('div'); src.className = 'source-badge';
  src.textContent = q.source === 'kanye' ? '🎤 kanye.rest' : q.source === 'dummyjson' ? '📚 dummyjson.com' : q.source === 'zenquotes' ? '📚 zenquotes.io' : '📝 lokal';
  card.appendChild(txt); card.appendChild(auth); card.appendChild(src);
  d.appendChild(card);
  var sv = document.createElement('button'); sv.className = 'btn-primary'; sv.textContent = '💾 Merken';
  sv.onclick = (function(qq) { return function() { saveQuote(qq); }; })(q);
  d.appendChild(sv);
}

function saveQuote(q) {
  var exists = savedQuotes.some(function(s) { return s.text === q.text; });
  if (exists) { setQS('Bereits gespeichert!', ''); return; }
  savedQuotes.push(q);
  document.getElementById('cntSaved').textContent = savedQuotes.length;
  try { sessionStorage.setItem('wmc_savedQuotes', JSON.stringify(savedQuotes)); } catch(e) {}
  renderSaved(); setQS('Gespeichert ✓', 'ok');
}
function deleteQuote(idx) {
  savedQuotes.splice(idx, 1);
  document.getElementById('cntSaved').textContent = savedQuotes.length;
  try { sessionStorage.setItem('wmc_savedQuotes', JSON.stringify(savedQuotes)); } catch(e) {}
  renderSaved();
}
function clearAll() { savedQuotes = []; document.getElementById('cntSaved').textContent = 0; try { sessionStorage.removeItem('wmc_savedQuotes'); } catch(e) {} renderSaved(); }

function renderSaved() {
  document.getElementById('savedCountLbl').textContent = savedQuotes.length + ' Zitate gespeichert';
  var g = document.getElementById('savedGrid');
  if (!savedQuotes.length) { g.innerHTML = '<div class="empty-state">Noch keine Daten gespeichert.</div>'; return; }
  g.innerHTML = '';
  savedQuotes.forEach(function(q, i) {
    var card = document.createElement('div'); card.className = 'saved-card';
    var sq   = document.createElement('div'); sq.className = 'sq'; sq.textContent = '"' + q.text + '"';
    var sa   = document.createElement('div'); sa.className = 'sa'; sa.textContent = '— ' + q.author;
    var src  = document.createElement('div'); src.className = 'src-sm';
    src.textContent = q.source === 'kanye' ? '🎤 kanye.rest' : q.source === 'dummyjson' ? '📚 dummyjson.com' : q.source === 'zenquotes' ? '📚 zenquotes.io' : '📝 lokal';
    var del  = document.createElement('button'); del.className = 'btn-danger';
    del.style.cssText = 'padding:3px 8px;font-size:0.72rem;margin-top:6px;';
    del.textContent = '✕ Entfernen';
    del.onclick = (function(ii) { return function() { deleteQuote(ii); }; })(i);
    card.appendChild(sq); card.appendChild(sa); card.appendChild(src); card.appendChild(del);
    g.appendChild(card);
  });
}
function exportSaved() {
  var data = savedQuotes.map(function(q) { return {text: q.text, author: q.author, source: q.source}; });
  exportList(data, 'exportFmtZ', 'gespeicherte_zitate');
}
function setQS(msg, type) { var b = document.getElementById('quoteStatus'); b.textContent = msg; b.className = 'status-bar ' + (type || ''); }

initSwitcher('abschluss', 'JS Abschlussprojekt', 'data:image/png;base64,');
}

/* ── Seite 4 – Fakten ──────────────────────── */
if (window.location.pathname.endsWith('abschluss_4_fakten.html') || document.title.includes('Fakten')) {
var FALLBACK_FACTS = [
  {text: "Oktopusse haben drei Herzen und blaues Blut.", source: "lokal", type: "fact"},
  {text: "Eine Schnecke kann bis zu 3 Jahre schlafen.", source: "lokal", type: "fact"},
  {text: "Bananen sind leicht radioaktiv.", source: "lokal", type: "fact"},
  {text: "Honig wird niemals schlecht – in Pharaonen-Gräbern gefundener Honig war noch essbar.", source: "lokal", type: "fact"},
  {text: "Ein Hai ist der einzige Fisch der zwinkern kann.", source: "lokal", type: "fact"},
  {text: "Ameisen schlafen nie und haben keine Lunge.", source: "lokal", type: "fact"},
  {text: "Schmetterlinge schmecken mit ihren Füßen.", source: "lokal", type: "fact"},
  {text: "Ein Krokodil kann seine Zunge nicht herausstrecken.", source: "lokal", type: "fact"}
];

var factHistory = [], factCount = 0;
try { var _fh = sessionStorage.getItem('wmc_factHistory'); if (_fh) { factHistory = JSON.parse(_fh); document.getElementById('cntSaved').textContent = factHistory.length; renderHistory(); } } catch(e) {}

function loadFact() {
  setFS('Lade nutzloses Wissen…', 'loading');
  document.getElementById('factHero').innerHTML = '<div class="empty-state">⏳ Verbinde…</div>';
  fetch('https://uselessfacts.jsph.pl/api/v2/facts/random?language=en')
    .then(function(r) { return r.json(); })
    .then(function(data) {
      factCount++; document.getElementById('cntFacts').textContent = factCount;
      renderFact({text: data.text, source: data.source_url || 'uselessfacts.jsph.pl', type: 'fact'});
      setFS('', '');
    })
    .catch(function() {
      // Try allorigins proxy
      fetch('https://api.allorigins.win/get?url=' + encodeURIComponent('https://uselessfacts.jsph.pl/api/v2/facts/random?language=en'))
        .then(function(r) { return r.json(); })
        .then(function(wrap) {
          var data = JSON.parse(wrap.contents);
          factCount++; document.getElementById('cntFacts').textContent = factCount;
          renderFact({text: data.text, source: 'uselessfacts.jsph.pl', type: 'fact'});
          setFS('', '');
        })
        .catch(function() {
          var f = FALLBACK_FACTS[Math.floor(Math.random() * FALLBACK_FACTS.length)];
          factCount++; document.getElementById('cntFacts').textContent = factCount;
          renderFact(f); setFS('Lokaler Fakt (API offline)', '');
        });
    });
}

function renderFact(fact) {
  var hero = document.getElementById('factHero'); hero.innerHTML = '';
  var card = document.createElement('div'); card.className = 'fact-card';
  var txt  = document.createElement('div'); txt.className = 'fact-text'; txt.textContent = fact.text;
  var src  = document.createElement('div'); src.className = 'fact-source'; src.textContent = 'Quelle: ' + fact.source;
  var sv   = document.createElement('button'); sv.className = 'btn-primary'; sv.textContent = '💾 Merken';
  sv.onclick = (function(f) { return function() { saveFact(f); }; })(fact);
  card.appendChild(txt); card.appendChild(src); card.appendChild(sv);
  hero.appendChild(card);
}
function saveFact(fact) {
  var exists = factHistory.some(function(f) { return f.text === fact.text; });
  if (exists) return;
  factHistory.unshift(fact);
  document.getElementById('cntSaved').textContent = factHistory.length;
  try { sessionStorage.setItem('wmc_factHistory', JSON.stringify(factHistory)); } catch(e) {}
  renderHistory();
}
function deleteFact(idx) { factHistory.splice(idx, 1); document.getElementById('cntSaved').textContent = factHistory.length; try { sessionStorage.setItem('wmc_factHistory', JSON.stringify(factHistory)); } catch(e) {} renderHistory(); }
function clearHistory() { factHistory = []; document.getElementById('cntSaved').textContent = 0; try { sessionStorage.removeItem('wmc_factHistory'); } catch(e) {} renderHistory(); }

function renderHistory() {
  document.getElementById('historyCount').textContent = factHistory.length + ' Fakten gespeichert';
  var list = document.getElementById('historyList');
  if (!factHistory.length) { list.innerHTML = '<div class="empty-state">Noch keine Daten gespeichert.</div>'; return; }
  list.innerHTML = '';
  factHistory.forEach(function(f, i) {
    var item  = document.createElement('div'); item.className = 'history-item';
    var p     = document.createElement('p'); p.textContent = f.text;
    var right = document.createElement('div'); right.className = 'hi-right';
    var src   = document.createElement('div'); src.className = 'src-sm'; src.textContent = f.source;
    var del   = document.createElement('button'); del.className = 'btn-danger';
    del.style.cssText = 'padding:3px 7px;font-size:0.72rem;';
    del.textContent = '✕';
    del.onclick = (function(ii) { return function() { deleteFact(ii); }; })(i);
    right.appendChild(src); right.appendChild(del);
    item.appendChild(p); item.appendChild(right);
    list.appendChild(item);
  });
}
function exportHistory() {
  var data = factHistory.map(function(f) { return {text: f.text, source: f.source, type: f.type || 'fact'}; });
  exportList(data, 'exportFmtF', 'gespeicherte_fakten');
}
function setFS(msg, type) { var b = document.getElementById('factStatus'); b.textContent = msg; b.className = 'status-bar ' + (type || ''); }

initSwitcher('abschluss', 'JS Abschlussprojekt', 'data:image/png;base64,');
}

